INSERT INTO room_types (property_id, name, description, area_sqm, bed_configuration, max_occupancy, view_type, total_rooms, base_price, is_active, updated_at) SELECT (SELECT id FROM properties WHERE slug = 'ai-binh-minh-ho-chi-minh-vn' LIMIT 1), 'Standard Room', '4-star hotel', '28', '1 queen bed', 2, NULL, 6, '1500000', true, now() WHERE (SELECT id FROM properties WHERE slug = 'ai-binh-minh-ho-chi-minh-vn' LIMIT 1) IS NOT NULL AND NOT EXISTS (SELECT 1 FROM room_types WHERE property_id = (SELECT id FROM properties WHERE slug = 'ai-binh-minh-ho-chi-minh-vn' LIMIT 1) AND name = 'Standard Room');
INSERT INTO rate_plans (room_type_id, name, meal_plan, refundable, base_price, is_active, updated_at) SELECT (SELECT id FROM room_types WHERE property_id = (SELECT id FROM properties WHERE slug = 'ai-binh-minh-ho-chi-minh-vn' LIMIT 1) AND name = 'Standard Room' LIMIT 1), 'Standard Rate', 'room_only'::meal_plan_enum, true, '1500000', true, now() WHERE (SELECT id FROM room_types WHERE property_id = (SELECT id FROM properties WHERE slug = 'ai-binh-minh-ho-chi-minh-vn' LIMIT 1) AND name = 'Standard Room' LIMIT 1) IS NOT NULL AND NOT EXISTS (SELECT 1 FROM rate_plans WHERE room_type_id = (SELECT id FROM room_types WHERE property_id = (SELECT id FROM properties WHERE slug = 'ai-binh-minh-ho-chi-minh-vn' LIMIT 1) AND name = 'Standard Room' LIMIT 1) AND name = 'Standard Rate');
