INSERT INTO properties (partner_id, slug, name, property_type, description, address, city, district, country_code, latitude, longitude, star_rating, avg_rating, total_reviews, check_in_time, check_out_time, status, updated_at) SELECT (SELECT id FROM partner_profiles WHERE id = 3 LIMIT 1), 'minh-chien-hotel-a-lat-vn', 'MINH CHIEN Hotel', 'hotel'::property_type_enum, 'MINH CHIEN Hotel is an imported hotel profile in Đà Lạt. Some fields were filled automatically for preview.', 'Đà Lạt, Vietnam', 'Đà Lạt', NULL, 'VN', '10.762622', '106.660172', 4, '8.4', 120, '14:00:00', '12:00:00', 'pending_review'::property_status_enum, now() WHERE (SELECT id FROM partner_profiles WHERE id = 3 LIMIT 1) IS NOT NULL ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, property_type = EXCLUDED.property_type, description = EXCLUDED.description, address = EXCLUDED.address, city = EXCLUDED.city, district = EXCLUDED.district, country_code = EXCLUDED.country_code, latitude = EXCLUDED.latitude, longitude = EXCLUDED.longitude, star_rating = EXCLUDED.star_rating, avg_rating = EXCLUDED.avg_rating, total_reviews = EXCLUDED.total_reviews, check_in_time = EXCLUDED.check_in_time, check_out_time = EXCLUDED.check_out_time, status = EXCLUDED.status, updated_at = now();
INSERT INTO property_policies (property_id, cancellation_type, free_cancel_hours, check_in_from, check_in_until, check_out_until, pets_allowed, smoking_allowed, children_allowed, min_child_age, custom_rules, accepted_payment_methods, updated_at) SELECT (SELECT id FROM properties WHERE slug = 'minh-chien-hotel-a-lat-vn' LIMIT 1), 'free'::cancellation_type_enum, 24, '14:00:00', '23:59:00', '12:00:00', false, false, false, 6, 'Free cancellation up to 24 hours before check-in.', '["credit_card","bank_transfer","pay_later"]'::jsonb, now() WHERE (SELECT id FROM properties WHERE slug = 'minh-chien-hotel-a-lat-vn' LIMIT 1) IS NOT NULL ON CONFLICT (property_id) DO UPDATE SET cancellation_type = EXCLUDED.cancellation_type, free_cancel_hours = EXCLUDED.free_cancel_hours, check_in_from = EXCLUDED.check_in_from, check_in_until = EXCLUDED.check_in_until, check_out_until = EXCLUDED.check_out_until, pets_allowed = EXCLUDED.pets_allowed, smoking_allowed = EXCLUDED.smoking_allowed, children_allowed = EXCLUDED.children_allowed, min_child_age = EXCLUDED.min_child_age, custom_rules = EXCLUDED.custom_rules, accepted_payment_methods = EXCLUDED.accepted_payment_methods, updated_at = now();
