INSERT INTO properties (partner_id, slug, name, property_type, description, address, city, district, country_code, latitude, longitude, star_rating, avg_rating, total_reviews, check_in_time, check_out_time, status, updated_at) SELECT (SELECT id FROM partner_profiles WHERE id = 3 LIMIT 1), 'khach-san-thanh-tam-ho-chi-minh-vn', 'Khách sạn Thanh Tâm', 'hotel'::property_type_enum, 'Khách sạn Thanh Tâm is an imported hotel profile in Hồ Chí Minh. Some fields were filled automatically for preview.', 'Hồ Chí Minh, Vietnam', 'Hồ Chí Minh', NULL, 'VN', '10.762622', '106.660172', 4, '8.4', 120, '14:00:00', '12:00:00', 'pending_review'::property_status_enum, now() WHERE (SELECT id FROM partner_profiles WHERE id = 3 LIMIT 1) IS NOT NULL ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, property_type = EXCLUDED.property_type, description = EXCLUDED.description, address = EXCLUDED.address, city = EXCLUDED.city, district = EXCLUDED.district, country_code = EXCLUDED.country_code, latitude = EXCLUDED.latitude, longitude = EXCLUDED.longitude, star_rating = EXCLUDED.star_rating, avg_rating = EXCLUDED.avg_rating, total_reviews = EXCLUDED.total_reviews, check_in_time = EXCLUDED.check_in_time, check_out_time = EXCLUDED.check_out_time, status = EXCLUDED.status, updated_at = now();
