INSERT INTO daily_rates (rate_plan_id, date, price, available_qty, min_stay, updated_at) SELECT (SELECT id FROM rate_plans WHERE room_type_id = (SELECT id FROM room_types WHERE property_id = (SELECT id FROM properties WHERE slug = 'can-ho-dich-vu-lancaster-ho-chi-minh-official-ho-chi-minh-vn' LIMIT 1) AND name = 'Suite' LIMIT 1) AND name = 'Standard Rate' LIMIT 1), day::date, '3200000', 2, 1, now() FROM generate_series(CURRENT_DATE, CURRENT_DATE + INTERVAL '180 days', INTERVAL '1 day') AS day WHERE (SELECT id FROM rate_plans WHERE room_type_id = (SELECT id FROM room_types WHERE property_id = (SELECT id FROM properties WHERE slug = 'can-ho-dich-vu-lancaster-ho-chi-minh-official-ho-chi-minh-vn' LIMIT 1) AND name = 'Suite' LIMIT 1) AND name = 'Standard Rate' LIMIT 1) IS NOT NULL ON CONFLICT (rate_plan_id, date) DO UPDATE SET price = EXCLUDED.price, available_qty = EXCLUDED.available_qty, min_stay = EXCLUDED.min_stay, updated_at = now();
